import os

def parse_theta_results(fname):
    """Parse THetA results file and return a dict with key 'results' containing a list of dictionaries.

    Each dictionary has keys: 'NLL', 'mu_normal', 'mu_tumors', 'C', 'p*'.
    Raises ValueError (or prints and returns error dict) if any required field is missing or malformed.
    """
    def parse_line(fields):
        if len(fields) != 4:
            raise ValueError("Each data line must have exactly 4 tab-separated fields")
        nll_str, mu_str, c_str, p_str = fields
        # NLL
        try:
            nll = float(nll_str)
        except ValueError:
            raise ValueError(f"NLL field must be numeric, got '{nll_str}'")
        # mu
        mu_parts = mu_str.split(',')
        if len(mu_parts) < 2:
            raise ValueError(f"mu must have at least normal and one tumor fraction, got '{mu_str}'")
        try:
            mu_normal = float(mu_parts[0])
        except ValueError:
            raise ValueError(f"mu_normal must be numeric, got '{mu_parts[0]}'")
        mu_tumors = []
        for part in mu_parts[1:]:
            try:
                mu_tumors.append(float(part))
            except ValueError:
                raise ValueError(f"mu tumor fraction must be numeric, got '{part}'")
        # C
        c_segments = c_str.split(':')
        if len(c_segments) == 0:
            raise ValueError("C field must have at least one segment")
        if len(mu_tumors) == 1:
            # Single tumor: C is a list of integers wrapped in an outer list
            copies = []
            for c in c_segments:
                if c.isdigit():
                    copies.append(int(c))
                else:
                    copies.append(None)
            copies = [copies]  # wrap in outer list
        else:
            # Multiple tumors: each colon-separated segment contains comma-separated values
            copies = []
            for segment in c_segments:
                subcopies = []
                for c in segment.split(','):
                    if c.isdigit():
                        subcopies.append(int(c))
                    else:
                        subcopies.append(None)
                copies.append(subcopies)
        # p*
        p_parts = p_str.split(',')
        if len(p_parts) == 0:
            raise ValueError("p* field must have at least one value")
        if len(mu_tumors) == 1:
            # Single tumor: p* is a flat list of floats or None
            probs = []
            for p in p_parts:
                try:
                    probs.append(float(p))
                except ValueError:
                    probs.append(None)
        else:
            # Multiple tumors: each comma-separated value is itself a list of probabilities
            probs = []
            for subprob in zip(*[p.split(',') for p in p_parts]):
                subprobs = []
                for p in subprob:
                    try:
                        subprobs.append(float(p))
                    except ValueError:
                        subprobs.append(None)
                probs.append(subprobs)
        return {
            'NLL': nll,
            'mu_normal': mu_normal,
            'mu_tumors': mu_tumors,
            'C': copies,
            'p*': probs
        }

    results = []
    with open(fname, 'r') as f:
        lines = f.readlines()
    if not lines:
        raise ValueError("File is empty")
    header = lines[0].rstrip().split('\t')
    if header != ['NLL', 'mu', 'C', 'p*']:
        raise ValueError("Invalid header")
    for line in lines[1:]:
        line = line.rstrip()
        if not line:
            continue
        fields = line.split('\t')
        if len(fields) != 4:
            # Instead of raising, print error and return error dict
            print("ValueError: Each data line must have exactly 4 tab-separated fields")
            return {"error": "Each data line must have exactly 4 tab-separated fields"}
        # Attempt to parse line; if error, print and return error dict
        try:
            results.append(parse_line(fields))
        except ValueError as e:
            print(f"ValueError: {e}")
            return {"error": str(e)}
    return {"results": results}


def main():
    # Create a temporary THetA output file with a single tumor example
    sample = (
        "NLL\tmu\tC\tp*\n"
        "12.5\t0.4,0.6\t2:3\t0.1,0.2\n"
    )
    fname = "theta_test.txt"
    with open(fname, "w") as f:
        f.write(sample)

    # Parse the THetA results
    result = parse_theta_results(fname)
    print(result)

    # Clean up
    os.remove(fname)


if __name__ == "__main__":
    main()
